<h2>Fee Payments</h2><form class="card form-grid" method="post"><label>Fee account<select name="fee_id"><?php foreach ($accounts as $a): ?><option value="<?= e($a['id']) ?>"><?= e($a['admission_no'].' '.$a['first_name'].' '.$a['last_name'].' Balance KES '.$a['balance']) ?></option><?php endforeach; ?></select></label><label>Student ID<input type="number" name="student_id" required></label><label>Amount<input type="number" step="0.01" name="amount" required></label><label>Method<select name="method"><option value="mpesa">M-Pesa</option><option value="cash">Cash</option><option value="bank">Bank</option><option value="cheque">Cheque</option></select></label><label>Reference<input name="reference" required></label><button>Record Payment & Generate Receipt</button></form>
